<?php
namespace App\Domain\Loans\Actions;
use App\Enums\LoanApplicationStatus;use App\Models\LoanApplication;use App\Models\LoanApprovalDecision;use Illuminate\Support\Facades\Auth;use Illuminate\Support\Facades\DB;use Illuminate\Validation\ValidationException;
class DecideLoanApplication{public function execute(LoanApplication $application,string $decision,?string $comment):LoanApplication{return DB::transaction(function()use($application,$decision,$comment){$application=LoanApplication::query()->with('workflow.steps')->lockForUpdate()->findOrFail($application->id);if(!in_array($application->status,[LoanApplicationStatus::Submitted,LoanApplicationStatus::UnderReview],true))throw ValidationException::withMessages(['status'=>['This application is not awaiting approval.']]);$step=$application->workflow->steps->firstWhere('sequence',$application->current_approval_sequence);if(!$step)throw ValidationException::withMessages(['workflow'=>['The current workflow step is invalid.']]);if(!Auth::user()?->hasPermission($step->required_permission))abort(403,'You do not have permission for this approval step.');LoanApprovalDecision::query()->create(['loan_application_id'=>$application->id,'approval_workflow_step_id'=>$step->id,'actor_id'=>Auth::id(),'decision'=>$decision,'comment'=>$comment,'decided_at'=>now()]);if($decision==='reject'){$application->update(['status'=>LoanApplicationStatus::Rejected,'rejected_at'=>now()]);return $application->refresh();}$count=$application->decisions()->where('approval_workflow_step_id',$step->id)->where('decision','approve')->count();if($count>=$step->minimum_approvals){$next=$application->workflow->steps->first(fn($candidate)=>$candidate->sequence>$step->sequence&&(!$candidate->minimum_amount_minor||$application->requested_principal_minor>=$candidate->minimum_amount_minor)&&(!$candidate->maximum_amount_minor||$application->requested_principal_minor<=$candidate->maximum_amount_minor));$application->update($next?['status'=>LoanApplicationStatus::UnderReview,'current_approval_sequence'=>$next->sequence]:['status'=>LoanApplicationStatus::Approved,'approved_at'=>now(),'current_approval_sequence'=>null]);}return $application->refresh();});}}
